BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?actor ?actorName WHERE {
  ?apsMission vocab:NamedElement_name "APS Mission" .
  ?apsMission rdf:type vocab:block .

  # Look for relationships that might connect to stakeholders/actors
  {
    ?dep vocab:Dependency_client ?apsMission .
    ?dep vocab:Dependency_supplier ?actor .
  } UNION {
    ?dep vocab:Dependency_supplier ?apsMission .
    ?dep vocab:Dependency_client ?actor .
  }

  ?actor rdf:type vocab:actor .
  ?actor vocab:NamedElement_name ?actorName .
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?relatedElem ?relatedName ?relatedType WHERE {
  ?apsMission vocab:NamedElement_name "APS Mission" .

  # Find elements connected to APS Mission via any relationship
  {
    ?rel vocab:Dependency_client ?apsMission .
    ?rel vocab:Dependency_supplier ?relatedElem .
  } UNION {
    ?rel vocab:Dependency_supplier ?apsMission .
    ?rel vocab:Dependency_client ?relatedElem .
  } UNION {
    ?rel vocab:Association_memberEnd ?apsMission .
    ?rel vocab:Association_memberEnd ?relatedElem .
    FILTER(?apsMission != ?relatedElem)
  }

  ?relatedElem vocab:NamedElement_name ?relatedName .
  ?relatedElem rdf:type ?relatedType .
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type ?ownerName WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS")))
  ?elem rdf:type ?type .
  OPTIONAL {
    ?elem vocab:Element_owner ?owner .
    ?owner vocab:NamedElement_name ?ownerName .
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?actor ?actorName WHERE {
  ?apsMission vocab:NamedElement_name "APS Mission" .
  ?apsMission rdf:type vocab:block .

  # Look for elements that are actors and have a relationship with APS Mission
  ?actor rdf:type vocab:actor .
  ?actor vocab:NamedElement_name ?actorName .

  {
    ?dep vocab:Dependency_client ?apsMission .
    ?dep vocab:Dependency_supplier ?actor .
  } UNION {
    ?dep vocab:Dependency_supplier ?apsMission .
    ?dep vocab:Dependency_client ?actor .
  }
}
